+        let filters = SummaryFilters {
+            since_ts: Some(1_700_050_000_000),
+            ..Default::default()
+        };
+
+        let generator = SummaryGenerator::new(&conn);
+        let summary = generator.generate(Some(&filters)).unwrap();
