+        let project_a = summary
+            .workspaces
+            .iter()
+            .find(|w| w.path == "/home/user/project-a")
+            .unwrap();
+        assert_eq!(project_a.conversation_count, 1);
+        assert_eq!(project_a.message_count, 3);
+        assert!(
+            project_a
